<script setup>
import { computed, ref } from 'vue';

const props = defineProps({
  isAuthenticated: {
    type: Boolean,
    default: false
  },
  user: {
    type: Object,
    default: null
  }
});

const emit = defineEmits(['toggle-auth', 'toggle-chat', 'logout']);

const menuOpen = ref(false);
const locationPending = ref(false);
const locationCity = ref('');
const locationCountry = ref('');
const hasSessionUser = computed(() => props.isAuthenticated && Boolean(props.user));
const displayName = computed(() => props.user?.fullName || props.user?.name || 'Utilisateur');

const locationLabel = computed(() => {
  if (locationCity.value && locationCountry.value) {
    return `${locationCity.value}, ${locationCountry.value}`;
  }
  return 'Activer la localisation';
});

function closeMenu() {
  menuOpen.value = false;
}

function openAuthFromMenu() {
  closeMenu();
  emit('toggle-auth');
}

function openPrimaryMenuAction() {
  if (hasSessionUser.value) {
    closeMenu();
    window.location.href = '/profil';
    return;
  }

  openAuthFromMenu();
}

function logoutFromMenu() {
  emit('logout');
  closeMenu();
}

function getCurrentPosition() {
  return new Promise((resolve, reject) => {
    if (!navigator.geolocation) {
      reject(new Error('unsupported'));
      return;
    }

    navigator.geolocation.getCurrentPosition(resolve, reject, {
      enableHighAccuracy: true,
      timeout: 10000,
      maximumAge: 300000
    });
  });
}

async function reverseGeocode(lat, lon) {
  const response = await fetch(
    `https://nominatim.openstreetmap.org/reverse?format=jsonv2&lat=${lat}&lon=${lon}&accept-language=fr`,
    {
      headers: {
        Accept: 'application/json'
      }
    }
  );

  if (!response.ok) {
    throw new Error('reverse-failed');
  }

  return response.json();
}

async function activateLocation() {
  if (locationPending.value) {
    return;
  }

  locationPending.value = true;
  try {
    const position = await getCurrentPosition();
    const { latitude, longitude } = position.coords;
    const data = await reverseGeocode(latitude, longitude);
    const address = data.address || {};

    locationCity.value =
      address.city ||
      address.town ||
      address.village ||
      address.municipality ||
      address.country ||
      '';
    locationCountry.value = address.country || '';
  } catch (error) {
    locationCity.value = '';
    locationCountry.value = '';
  } finally {
    locationPending.value = false;
  }
}
</script>
